// MARK: - Models

struct Stock: Identifiable, Codable, Hashable {
    let id: String // Symbol
    let name: String
    var currentPrice: Double
    var previousClose: Double?
    var change: Double {
        guard let prev = previousClose else { return 0 }
        return currentPrice - prev
    }
    var changePercent: Double {
        guard let prev = previousClose, prev != 0 else { return 0 }
        return (change / prev) * 100
    }
}

struct Trade: Identifiable, Codable {
    let id = UUID()
    let stockSymbol: String
    let type: TradeType
    let quantity: Int
    let price: Double
    let timestamp: Date
}

enum TradeType: String, Codable {
    case buy = "Buy"
    case sell = "Sell"
}

struct PortfolioHolding: Identifiable, Codable {
    let id: String // Stock Symbol
    var quantity: Int
    var averageCost: Double
    var currentPrice: Double // To be updated from real-time data
    var totalCost: Double {
        Double(quantity) * averageCost
    }
    var marketValue: Double {
        Double(quantity) * currentPrice
    }
    var profitLoss: Double {
        marketValue - totalCost
    }
    var profitLossPercent: Double {
        guard totalCost != 0 else { return 0 }
        return (profitLoss / totalCost) * 100
    }
}

struct User: Identifiable, Codable {
    let id: String
    let username: String
    var cashBalance: Double
}

