// MARK: - Real-time Service

class RealtimeService: ObservableObject {
    static let shared = RealtimeService()

    @Published var liveStockPrices: [String: Double] = [:]
    private var timer: AnyCancellable?
    private var cancellables = Set<AnyCancellable>()

    private init() {
        startPriceUpdates()
    }

    private func startPriceUpdates() {
        timer = Timer.publish(every: 2.0, on: .main, in: .common)
            .autoconnect()
            .sink { [weak self] _ in
                self?.updateMockPrices()
            }
    }

    private func updateMockPrices() {
        var updatedPrices = liveStockPrices
        if updatedPrices.isEmpty { // Initialize if empty
            updatedPrices = APIService.shared.mockStocks.reduce(into: [:]) { $0[$1.id] = $1.currentPrice }
        }

        for (symbol, currentPrice) in updatedPrices {
            let change = Double.random(in: -1.5...1.5) // Simulate price fluctuation
            let newPrice = max(0.01, currentPrice + change) // Ensure price doesn't go below zero
            updatedPrices[symbol] = (newPrice * 100).rounded() / 100 // Round to 2 decimal places
        }
        liveStockPrices = updatedPrices
    }

    func getLivePrice(for symbol: String) -> Double? {
        liveStockPrices[symbol]
    }
}

